from flask import Flask, request, session, jsonify
from flask_wtf.csrf import CSRFProtect
from werkzeug.security import generate_password_hash, check_password_hash
import secrets

app = Flask(__name__)
app.config['SECRET_KEY'] = secrets.token_hex(16)
csrf = CSRFProtect(app)

# Mock user data storage
users = {
    'testuser': {
        'email': 'test@example.com',
        'password_hash': generate_password_hash('password123'),
        'two_factor_enabled': False,
        'two_factor_secret': None
    }
}

def get_current_user():
    username = session.get('username')
    return users.get(username)

@app.route('/api/profile', methods=['POST'])
@csrf.exempt  # Will be handled by session-based CSRF protection
def update_profile():
    user = get_current_user()
    if not user:
        return jsonify({'error': 'Unauthorized'}), 401
    
    data = request.get_json()
    if not data:
        return jsonify({'error': 'No data provided'}), 400
    
    # Update email
    if 'email' in data:
        user['email'] = data['email']
    
    # Update password
    if 'password' in data:
        if not 'current_password' in data:
            return jsonify({'error': 'Current password required'}), 400
        if not check_password_hash(user['password_hash'], data['current_password']):
            return jsonify({'error': 'Current password incorrect'}), 400
        user['password_hash'] = generate_password_hash(data['password'])
    
    # Update 2FA settings
    if 'two_factor_enabled' in data:
        user['two_factor_enabled'] = data['two_factor_enabled']
        if data['two_factor_enabled'] and not user['two_factor_secret']:
            user['two_factor_secret'] = secrets.token_hex(16)
        elif not data['two_factor_enabled']:
            user['two_factor_secret'] = None
    
    return jsonify({'message': 'Profile updated successfully'})

# Add CSRF token endpoint for SPA
@app.route('/api/csrf-token', methods=['GET'])
def get_csrf_token():
    return jsonify({'csrf_token': session.get('csrf_token', '')})

# Ensure secure session cookies
@app.before_request
def ensure_secure_session():
    if request.is_secure:
        session.permanent = True
        app.config['SESSION_COOKIE_SECURE'] = True
        app.config['SESSION_COOKIE_HTTPONLY'] = True
        app.config['SESSION_COOKIE_SAMESITE'] = 'Lax'